{"type":"message","id":"7754fcf7","parentId":"618fd327","timestamp":"2026-03-19T16:55:32.370Z","message":{"role":"toolResult","toolCallId":"ollama_call_66ac1137-2854-4f24-8c2c-c23ff456c6ce","toolName":"read","content":[{"type":"text","text":"#!/usr/bin/env python3\nfrom __future__ import annotations\n\nfrom pathlib import Path\nimport hashlib\nimport json\nimport math\nimport re\nfrom collections import Counter, defaultdict\nfrom urllib import request\n\nROOT = Path('/home/tiny4lurv/.openclaw/workspace')\nCHUNKS = ROOT / 'rag' / 'index' / 'chunks.jsonl'\nOUT = ROOT / 'rag' / 'index' / 'vector_index.json'\nTOKEN_RE = re.compile(r\"[a-zA-Z][a-zA-Z0-9\\-]{1,}\")\n\n# Fallback params (stdlib-only semantic-ish hashing)\nFALLBACK_DIMS = 768\nNGRAM_MIN = 3\nNGRAM_MAX = 5\nOLLAMA_URL = 'http://127.0.0.1:11434/api/embed'\nOLLAMA_MODEL = 'nomic-embed-text'\nFASTEMBED_MODEL = 'BAAI/bge-small-en-v1.5'\n\n\ndef tokenize(text: str):\n    return [t.lower() for t in TOKEN_RE.findall(text)]\n\n\ndef l2_normalize(v):\n    norm = math.sqrt(sum(x * x for x in v))\n    if norm == 0:\n        return v\n    return [x / norm for x in v]\n\n\ndef hash_feature(s: str, dims: int):\n    h = hashlib.sha1(s.encode('utf-8')).digest()\n    idx = int.from_bytes(h[:4], 'big') % dims\n    sign = 1.0 if (h[4] & 1) == 0 else -1.0\n    return idx, sign\n\n\ndef char_ngrams(token: str):\n    t = f\"^{token}$\"\n    n = len(t)\n    for k in range(NGRAM_MIN, NGRAM_MAX + 1):\n        if n < k:\n            continue\n        for i in range(0, n - k + 1):\n            yield t[i:i + k]\n\n\ndef build_fallback_embeddings(records):\n    df = defaultdict(int)\n    tokenized = []\n    for r in records:\n        toks = tokenize(r['text'])\n        tokenized.append(toks)\n        for t in set(toks):\n            df[t] += 1\n\n    N = max(1, len(records))\n\n    embeddings = []\n    for toks in tokenized:\n        vec = [0.0] * FALLBACK_DIMS\n        tf = Counter(toks)\n        for tok, freq in tf.items():\n            idf = math.log(1.0 + (N + 1) / (df[tok] + 1))\n            w = (1.0 + math.log(freq)) * idf\n            idx, sign = hash_feature(f\"tok::{tok}\", FALLBACK_DIMS)\n            vec[idx] += sign * w\n            for ng in char_ngrams(tok):\n                ng_idx, ng_sign = hash_feature(f\"ng::{ng}\", FALLBACK_DIMS)\n                vec[ng_idx] += ng_sign * (w * 0.25)\n        embeddings.append(l2_normalize(vec))\n\n    return {\n        'backend': 'fallback_hash_embedding',\n        'dims': FALLBACK_DIMS,\n        'notes': 'Approximate semantic proxy with no external dependencies.',\n        'embeddings': embeddings,\n    }\n\n\ndef try_fastembed_embeddings(records):\n    try:\n        from fastembed import TextEmbedding\n    except Exception:\n        return None\n\n    model = TextEmbedding(model_name=FASTEMBED_MODEL)\n    embeddings = []\n    batch_size = 32\n    try:\n        for i in range(0, len(records), batch_size):\n            texts = [r['text'] for r in records[i:i + batch_size]]\n            for e in model.embed(texts):\n                embeddings.append(l2_normalize(list(map(float, e.tolist()))))\n    except Exception:\n        return None\n\n    if not embeddings or len(embeddings) != len(records):\n        return None\n    dims = len(embeddings[0]) if embeddings else 0\n    return {\n        'backend': 'fastembed',\n        'model': FASTEMBED_MODEL,\n        'dims': dims,\n        'notes': 'Dense embeddings via fastembed/ONNX transformer model.',\n        'embeddings': embeddings,\n    }\n\n\ndef try_ollama_embeddings(records):\n    embeddings = []\n    batch_size = 48\n    for i in range(0, len(records), batch_size):\n        texts = [r['text'] for r in records[i:i + batch_size]]\n        payload = json.dumps({'model': OLLAMA_MODEL, 'input': texts}).encode('utf-8')\n        req = request.Request(\n            OLLAMA_URL,\n            data=payload,\n            headers={'Content-Type': 'application/json'},\n            method='POST',\n        )\n        try:\n            with request.urlopen(req, timeout=600) as resp:\n                data = json.loads(resp.read().decode('utf-8'))\n        except Exception:\n            return None\n\n        embs = data.get('embeddings')\n        if not embs or len(embs) != len(texts):\n            return None\n        embeddings.extend(l2_normalize(list(map(float, e))) for e in embs)\n\n    dims = len(embeddings[0]) if embeddings else 0\n    return {\n        'backend': 'ollama_embed',\n        'model': OLLAMA_MODEL,\n        'dims': dims,\n        'notes': 'Dense embeddings via local Ollama embedding model.',\n        'embeddings': embeddings,\n    }\n\n\ndef main():\n    records = []\n    with CHUNKS.open('r', encoding='utf-8') as f:\n        for line in f:\n            r = json.loads(line)\n            records.append({\n                'id': r['id'],\n                'path': r['path'],\n                'source_type': r['source_type'],\n                'chunk_index': r['chunk_index'],\n                'text': r['text'],\n            })\n\n    if not records:\n        raise SystemExit('No chunk records found. Run build_chunks.py first.')\n\n    vec_data = try_fastembed_embeddings(records)\n    if vec_data is None:\n        vec_data = try_ollama_embeddings(records)\n    if vec_data is None:\n        vec_data = build_fallback_embeddings(records)\n\n    out = {\n        'meta': {\n            'num_docs': len(records),\n            'backend': vec_data['backend'],\n            'dims': vec_data['dims'],\n            'notes': vec_data['notes'],\n        },\n        'docs': records,\n        'vectors': vec_data['embeddings'],\n    }\n    if 'model' in vec_data:\n        out['meta']['model'] = vec_data['model']\n\n    OUT.write_text(json.dumps(out, ensure_ascii=False), encoding='utf-8')\n    print(f\"Indexed {len(records)} vectors using {out['meta']['backend']} -> {OUT}\")\n\n\nif __name__ == '__main__':\n    main()\n"}],"isError":false,"timestamp":1773939332368}}
