import sys
from pathlib import Path

SESSION_DIR = Path.home() / ".openclaw/agents/main/sessions"

# Find sessions modified between Mar 17-27
window_sessions = []
for f in SESSION_DIR.glob("*.jsonl"):
    mtime = f.stat().st_mtime
    # 2026-03-17 = 1773696000, 2026-03-28 = 1774809600
    if 1773696000 <= mtime < 1774809600:
        window_sessions.append(f)

print(f"Sessions in window: {len(window_sessions)}")
for s in sorted(window_sessions):
    print(f"  {s.name}  {s.stat().st_mtime}")

# Search for note instructions
patterns = [
    "take notes", "make a note", "remember this", "note this",
    "don't forget", "I want you to remember", "save.*to",
    "write.*down", "log.*this", "add.*to.*memory"
]

import re

for sess_file in sorted(window_sessions):
    print(f"\n=== {sess_file.name} ===")
    matches = []
    try:
        with open(sess_file) as f:
            for line in f:
                try:
                    obj = json.loads(line)
                    if obj.get("type") == "message":
                        msg = obj.get("message", {})
                        if msg.get("role") == "user":
                            content = msg.get("content", [])
                            for block in content:
                                if block.get("type") == "text":
                                    text = block["text"]
                                    for pat in patterns:
                                        if re.search(pat, text, re.I):
                                            ts = obj.get("timestamp", "?")
                                            matches.append((ts, text[:200]))
                except:
                    pass
    except Exception as e:
        print(f"  Error: {e}")

    if matches:
        for ts, text in matches:
            print(f"  [{ts}] {text[:150]}")
    else:
        print("  (no note instructions found)")
