import json
from pathlib import Path

sess = Path.home() / ".openclaw/agents/main/sessions/46e65f89-15c7-42d0-959a-8c00ee540bbe.jsonl"

with open(sess) as f:
    lines = f.readlines()

# Find user messages
for i, line in enumerate(lines):
    try:
        obj = json.loads(line)
        if obj.get("type") == "message":
            msg = obj.get("message", {})
            if msg.get("role") == "user":
                ts = obj.get("timestamp","")
                content = msg.get("content", [])
                for block in content:
                    if block.get("type") == "text":
                        text = block["text"].strip()
                        # Skip system-like content
                        if text.startswith("Sender (untrusted"):
                            continue
                        if text.startswith("{"):
                            continue
                        if text.startswith("System:"):
                            continue
                        if "[Subagent" in text:
                            continue
                        if len(text) > 15:
                            print(f"[{ts}] LINE {i}: {text[:300]}")
                            print()
                            break  # only first text block per message
    except:
        pass
